  router.post("/api/jobs/:id/complete", requireAuth, async (req: Request, res: Response) => {
    try {
      const job = await getJobById(req.params.id);
      if (!job) return res.status(404).json({ message: "Job not found" });

      if (job.status === "completed" || job.status === "canceled") {
        return res.status(409).json({ message: `Cannot complete a job that is ${job.status}` });
      }

      const now = new Date();
      const updatedJob = await updateJob(req.params.id, {
        status: "completed",
        startedAt: (job as any).startedAt || now,
        completedAt: now,
        endDatetime: now,
      });

      let nextJob = null;
      if (job.recurrence && job.recurrence !== "none") {
        const currentDate = new Date(job.startDatetime);
        let nextDate: Date;

        switch (job.recurrence) {
          case "weekly":
            nextDate = new Date(currentDate);
            nextDate.setDate(nextDate.getDate() + 7);
            break;
          case "biweekly":
            nextDate = new Date(currentDate);
            nextDate.setDate(nextDate.getDate() + 14);
            break;
          case "monthly":
            nextDate = new Date(currentDate);
            nextDate.setMonth(nextDate.getMonth() + 1);
            break;
          case "quarterly":
            nextDate = new Date(currentDate);
            nextDate.setMonth(nextDate.getMonth() + 3);
            break;
          default:
            nextDate = new Date(currentDate);
            nextDate.setDate(nextDate.getDate() + 7);
        }

        nextJob = await createJob({
          businessId: job.businessId,
          customerId: job.customerId || undefined,
          quoteId: job.quoteId || undefined,
          jobType: job.jobType,
          startDatetime: nextDate,
          recurrence: job.recurrence,
          internalNotes: job.internalNotes,
          address: job.address,
          total: job.total || undefined,
        });

        const checklist = await getChecklistByJob(job.id);
        for (let i = 0; i < checklist.length; i++) {
          await createChecklistItem({
            jobId: nextJob.id,
            label: checklist[i].label,
            sortOrder: checklist[i].sortOrder,
          });
        }
      }

      let ratingUrl: string | null = null;
      if (updatedJob.ratingToken) {
        ratingUrl = `${getPublicBaseUrl(req)}/rate/${updatedJob.ratingToken}`;
      }

      trackEvent(req.session.userId!, AnalyticsEvents.FIRST_JOB_COMPLETED, { jobId: job.id }).catch(() => {});

      // ── Badge: five_jobs_completed ────────────────────────────────────────
      if (job.businessId && req.session.userId) {
        pool.query(
          `SELECT COUNT(*) AS c FROM jobs WHERE business_id = $1 AND status = 'completed'`,
          [job.businessId]
        ).then(async (r) => {
          const count = parseInt(r.rows[0]?.c ?? "0", 10);
          if (count >= 5) {
            await maybeAwardBadge(job.businessId, req.session.userId!, "five_jobs_completed").catch(() => {});
          }
        }).catch(() => {});
      }

      return res.json({
        completedJob: updatedJob,
        nextJob,
        ratingUrl,
        message: nextJob
          ? `Job completed! Next ${job.recurrence} job scheduled.`
          : "Job completed!",
      });
    } catch (error: any) {
      console.error("Complete job error:", error);
      return res.status(500).json({ message: "Failed to complete job" });
    }
  });

